#### 2.7 `packages/generator-rest-client/src/type-map.ts`

Centralized Prisma-to-TypeScript type mapping:

```typescript
/**
 * Maps Prisma scalar type names to their TypeScript equivalents.
 *
 * Reference: packages/client-generator-js/src/utils/common.ts GraphQLScalarToJSTypeTable
 * We simplify for REST client use -- each Prisma type maps to exactly one TS type.
 */
export const PRISMA_SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',    // Decimal is serialized as string in JSON REST APIs
  DateTime: 'string',   // ISO 8601 string in JSON
  Json: 'unknown',      // arbitrary JSON value
  Bytes: 'string',      // base64-encoded string in JSON
}

/**
 * Convert a Prisma field type to a TypeScript type string.
 * For enum types, uses the enum name directly (they are generated as TS string union types).
 * For scalar types, uses the mapping table.
 * For unknown types, falls back to 'unknown'.
 */
export function prismaTypeToTypeScript(type: string, kind: string): string {
  if (kind === 'enum') {
    return type  // enum name -- the enum type will be generated separately
  }
  return PRISMA_SCALAR_TYPE_MAP[type] ?? 'unknown'
}
```

Rationale for the type mapping choices:
- `Decimal` -> `string`: JSON has no native decimal type; REST APIs serialize Decimal as string to avoid precision loss.
- `DateTime` -> `string`: JSON has no Date type; REST APIs use ISO 8601 strings.
- `BigInt` -> `bigint`: TypeScript has native bigint, though in practice JSON serialization uses strings. We use `bigint` for type safety in the generated code; the REST client's `fetch` wrapper will handle JSON parsing.
- `Bytes` -> `string`: Base64-encoded in JSON transport.
- `Json` -> `unknown`: Arbitrary JSON; `unknown` is safer than `any`.

#### 2.8 `packages/generator-rest-client/src/template.ts`

String template helpers for code generation. This is the core of the code generation logic.

**Functions in this module:**

**`generateHeader(baseUrlConfig: string | undefined): string`**
Generates the file header with:
- A warning comment that the file is auto-generated
- A `RestClientConfig` type with `baseUrl: string` and optional `headers`
- A `RestClient` class with private `config`, `request` helper method, and typed CRUD method factories

**`generateEnumType(enumDef: DatamodelEnum): string`**
Generates a TypeScript string union type for each Prisma enum:
```typescript
export type Status = 'ACTIVE' | 'INACTIVE' | 'PENDING'
```

**`generateModelInterface(model: Model, enumNames: Set<string>): string`**
Generates a TypeScript interface for a model, including only scalar and enum fields (skipping `object` and `unsupported` kind fields):
```typescript
export interface User {
  id: number
  email: string
  name: string | null
  role: Role
  createdAt: string
}
```

Handles:
- `isRequired: false` -> `T | null` (nullable field)
- `isList: true` -> `T[]` (array field)
- Both: `isList && !isRequired` -> `T[] | null`
- Enum fields: uses the enum type name directly

**`generateCreateInput(model: Model, enumNames: Set<string>): string`**
Generates a `CreateInput` type that omits fields with `isId: true && hasDefaultValue: true` (auto-increment IDs), `isReadOnly: true`, `isUpdatedAt: true`, and `isGenerated: true` fields, and makes fields with `hasDefaultValue: true` optional:
```typescript
export interface UserCreateInput {
  email: string
  name?: string | null
  role?: Role
}
```

**`generateUpdateInput(model: Model, enumNames: Set<string>): string`**
Generates an `UpdateInput` type where all fields are optional (Partial-like), excluding `isId`, `isReadOnly`, and `isGenerated` fields:
```typescript
export interface UserUpdateInput {
  email?: string
  name?: string | null
  role?: Role
}
```

**`generateWhereUniqueInput(model: Model): string`**
Generates a type for identifying a unique record. Uses `isId` fields, or falls back to `isUnique` fields:
```typescript
export interface UserWhereUniqueInput {
  id: number
}
```
For composite primary keys (from `model.primaryKey`), generates an intersection or object with all primary key fields.

**`generateModelCrud(modelName: string): string`**
Generates CRUD method definitions for a model as methods on the REST client class:
```typescript
async findMany{ModelName}(params?: { skip?: number; take?: number }): Promise<{ModelName}[]> {
  const query = params ? '?' + new URLSearchParams(
    Object.entries(params).filter(([_, v]) => v !== undefined).map(([k, v]) => [k, String(v)])
  ).toString() : ''
  return this.request<{ModelName}[]>(`/{modelNameLower}${query}`, { method: 'GET' })
}

async findUnique{ModelName}(where: {ModelName}WhereUniqueInput): Promise<{ModelName} | null> {
  // Extract the id value from where
  return this.request<{ModelName} | null>(`/{modelNameLower}/${this.extractId(where)}`, { method: 'GET' })
}

async create{ModelName}(data: {ModelName}CreateInput): Promise<{ModelName}> {
  return this.request<{ModelName}>(`/{modelNameLower}`, { method: 'POST', body: JSON.stringify(data) })
}

async update{ModelName}(where: {ModelName}WhereUniqueInput, data: {ModelName}UpdateInput): Promise<{ModelName}> {
  return this.request<{ModelName}>(`/{modelNameLower}/${this.extractId(where)}`, { method: 'PUT', body: JSON.stringify(data) })
}

async delete{ModelName}(where: {ModelName}WhereUniqueInput): Promise<{ModelName}> {
  return this.request<{ModelName}>(`/{modelNameLower}/${this.extractId(where)}`, { method: 'DELETE' })
}
```

**`generateRestClientClass(modelNames: string[]): string`**
Generates the `RestClient` class shell with:
- Constructor accepting `RestClientConfig`
- A private `request<T>` method using `fetch`
- A private `extractId` utility that pulls the first value from a where-unique object
- All model CRUD methods inlined via `generateModelCrud` calls

#### 2.9 `packages/generator-rest-client/src/generator.ts`

The main orchestrator. This module:

1. Receives `GeneratorOptions` from the handler
2. Extracts the output directory from `options.generator.output`
3. Iterates `options.dmmf.datamodel.enums` and `options.dmmf.datamodel.models`
4. Assembles the final file content by calling template functions
5. Creates the output directory (via `fs.mkdir` with `recursive: true`)
6. Writes the `rest-client.ts` file

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type { GeneratorOptions } from '@prisma/generator'
import {
  generateHeader,
  generateEnumType,
  generateModelInterface,
  generateCreateInput,
  generateUpdateInput,
  generateWhereUniqueInput,
  generateModelCrud,
  generateRestClientClass,
} from './template'

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output
  if (!output || !output.value) {
    throw new Error('No output directory specified for generator-rest-client')
  }
  const outputDir = output.value
  const result = generateRestClient(options)

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), result, 'utf-8')
}

export function generateRestClient(options: GeneratorOptions): string {
  const { models, enums } = options.dmmf.datamodel
  const enumNames = new Set(enums.map(e => e.name))
  const parts: string[] = []

  // 1. File header with auto-gen warning and config types
  parts.push(generateHeader())

  // 2. Enum types
  for (const enumDef of enums) {
    parts.push(generateEnumType(enumDef))
  }

  // 3. Model interfaces + input types
  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames))
    parts.push(generateCreateInput(model, enumNames))
    parts.push(generateUpdateInput(model, enumNames))
    parts.push(generateWhereUniqueInput(model))
  }

  // 4. REST client class with CRUD methods
  parts.push(generateRestClientClass(models.map(m => m.name)))

  return parts.join('\n\n') + '\n'
}
```

