import type { DMMF } from '@prisma/generator-helper'

import { prismaTypeToTypeScript } from './type-map'

/** Generate the auto-generated file header and shared types. */
export function generateHeader(): string {
  return `\
// ==========================================================================
// AUTO-GENERATED FILE - DO NOT EDIT
// Generated by @prisma/generator-rest-client
// ==========================================================================

export interface RestClientConfig {
  /** Base URL of the REST API (e.g. "https://api.example.com"). */
  baseUrl: string
  /** Optional headers sent with every request. */
  headers?: Record<string, string>
}`
}

/** Generate a TypeScript string union type from a Prisma enum. */
export function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${members}`
}

/**
 * Resolve the full TypeScript type string for a DMMF field, accounting for
 * nullability and list types.
 */
function fieldTypeString(field: DMMF.Field, enumNames: Set<string>): string {
  const base = prismaTypeToTypeScript(field.type, field.kind)
  let ts = field.isList ? `${base}[]` : base

  if (!field.isRequired) {
    ts += ' | null'
  }
  return ts
}

/** Return `true` for fields that belong in the read-side model interface. */
function isReadableField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/** Generate a TypeScript interface mirroring the model's scalar + enum fields. */
export function generateModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter(isReadableField)

  const lines = fields.map((f) => {
    const ts = fieldTypeString(f, enumNames)
    return `  ${f.name}: ${ts}`
  })

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generate a `CreateInput` type.
 *
 * Auto-increment IDs, `@updatedAt` fields, generated fields, and relation
 * fields are excluded. Fields with a default value or that are nullable are
 * made optional.
 */
export function generateCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (!isReadableField(f)) return false
    // Skip auto-increment / auto-generated primary keys
    if (f.isId && f.hasDefaultValue) return false
    if (f.isUpdatedAt) return false
    if (f.isGenerated) return false
    return true
  })

  const lines = fields.map((f) => {
    const ts = fieldTypeString(f, enumNames)
    const optional = f.hasDefaultValue || !f.isRequired ? '?' : ''
    return `  ${f.name}${optional}: ${ts}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generate an `UpdateInput` type.
 *
 * All mutable fields are optional. ID, read-only, and generated fields are
 * excluded since they cannot be changed through an update.
 */
export function generateUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (!isReadableField(f)) return false
    if (f.isId) return false
    if (f.isReadOnly) return false
    if (f.isGenerated) return false
    if (f.isUpdatedAt) return false
    return true
  })

  const lines = fields.map((f) => {
    const ts = fieldTypeString(f, enumNames)
    return `  ${f.name}?: ${ts}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generate a `WhereUniqueInput` type for identifying a single record.
 *
 * Uses `@id` fields first, then composite primary keys, then `@unique` fields.
 * Falls back to `Record<string, unknown>` if none are found.
 */
export function generateWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string {
  let idFields = model.fields.filter((f) => f.isId && isReadableField(f))

  // Composite primary key
  if (idFields.length === 0 && model.primaryKey) {
    const pkFieldNames = new Set(model.primaryKey.fields)
    idFields = model.fields.filter((f) => pkFieldNames.has(f.name) && isReadableField(f))
  }

  // Fall back to @unique fields
  if (idFields.length === 0) {
    idFields = model.fields.filter((f) => f.isUnique && isReadableField(f))
  }

  if (idFields.length === 0) {
    return `/** No @id or @unique field found; use an arbitrary key-value lookup. */\nexport type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }

  const lines = idFields.map((f) => {
    const ts = prismaTypeToTypeScript(f.type, f.kind)
    return `  ${f.name}: ${ts}`
  })

  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/** Generate the five CRUD methods for a single model as class method strings. */
export function generateModelCrud(modelName: string): string {
  const path = modelName.toLowerCase()
  return `\
  async findMany${modelName}(params?: { skip?: number; take?: number }): Promise<${modelName}[]> {
    const query = params
      ? '?' + new URLSearchParams(
          Object.entries(params)
            .filter(([, v]) => v !== undefined)
            .map(([k, v]) => [k, String(v)]),
        ).toString()
      : ''
    return this.request<${modelName}[]>(\`/${path}\${query}\`, { method: 'GET' })
  }

  async findUnique${modelName}(where: ${modelName}WhereUniqueInput): Promise<${modelName} | null> {
    return this.request<${modelName} | null>(\`/${path}/\${this.extractId(where)}\`, { method: 'GET' })
  }

  async create${modelName}(data: ${modelName}CreateInput): Promise<${modelName}> {
    return this.request<${modelName}>(\`/${path}\`, {
      method: 'POST',
      body: JSON.stringify(data),
    })
  }

  async update${modelName}(where: ${modelName}WhereUniqueInput, data: ${modelName}UpdateInput): Promise<${modelName}> {
    return this.request<${modelName}>(\`/${path}/\${this.extractId(where)}\`, {
      method: 'PUT',
      body: JSON.stringify(data),
    })
  }

  async delete${modelName}(where: ${modelName}WhereUniqueInput): Promise<${modelName}> {
    return this.request<${modelName}>(\`/${path}/\${this.extractId(where)}\`, {
      method: 'DELETE',
    })
  }`
}

/** Generate the complete `PrismaRestClient` class with CRUD methods for every model. */
export function generateRestClientClass(modelNames: string[]): string {
  const crudSections = modelNames.map((name) => generateModelCrud(name)).join('\n\n')

  return `\
export class PrismaRestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(config: RestClientConfig) {
    this.#baseUrl = config.baseUrl.replace(/\\/$/, '')
    this.#headers = {
      'Content-Type': 'application/json',
      ...config.headers,
    }
  }

  async #request<T>(path: string, init?: RequestInit): Promise<T> {
    const response = await fetch(\`\${this.#baseUrl}\${path}\`, {
      ...init,
      headers: { ...this.#headers, ...(init?.headers as Record<string, string>) },
    })
    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }

  /** Extract the first value from a where-unique object for use in a URL path segment. */
  private extractId(where: Record<string, unknown>): string {
    const values = Object.values(where)
    if (values.length === 0) {
      throw new Error('WhereUniqueInput must have at least one field')
    }
    return encodeURIComponent(String(values[0]))
  }

${crudSections}
}`
}

