import type { DMMF } from '@prisma/generator-helper';
import type { GeneratorOptions } from '@prisma/generator-helper';

/**
 * Generate a `CreateInput` type.
 *
 * Auto-increment IDs, `@updatedAt` fields, generated fields, and relation
 * fields are excluded. Fields with a default value or that are nullable are
 * made optional.
 */
export declare function generateCreateInput(model: DMMF.Model, enumNames: Set<string>): string;

/** Generate a TypeScript string union type from a Prisma enum. */
export declare function generateEnumType(enumDef: DMMF.DatamodelEnum): string;

/** Generate the auto-generated file header and shared types. */
export declare function generateHeader(): string;

/** Generate the five CRUD methods for a single model as class method strings. */
export declare function generateModelCrud(modelName: string): string;

/** Generate a TypeScript interface mirroring the model's scalar + enum fields. */
export declare function generateModelInterface(model: DMMF.Model, enumNames: Set<string>): string;

/**
 * Pure function that produces the full `rest-client.ts` source text from
 * generator options. Separated from file I/O so it can be unit-tested easily.
 */
export declare function generateRestClient(options: GeneratorOptions): string;

/** Generate the complete `PrismaRestClient` class with CRUD methods for every model. */
export declare function generateRestClientClass(modelNames: string[]): string;

/**
 * Generate an `UpdateInput` type.
 *
 * All mutable fields are optional. ID, read-only, and generated fields are
 * excluded since they cannot be changed through an update.
 */
export declare function generateUpdateInput(model: DMMF.Model, enumNames: Set<string>): string;

/**
 * Generate a `WhereUniqueInput` type for identifying a single record.
 *
 * Uses `@id` fields first, then composite primary keys, then `@unique` fields.
 * Falls back to `Record<string, unknown>` if none are found.
 */
export declare function generateWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string;

/**
 * `onGenerate` callback for the generator handler.
 *
 * Reads the DMMF from the provided options, generates a typed REST client
 * source file, and writes it to the configured output directory.
 */
export declare function onGenerate(options: GeneratorOptions): Promise<void>;

/**
 * Maps Prisma scalar type names to their TypeScript equivalents.
 *
 * Decimal and DateTime are represented as strings because JSON has no native
 * types for arbitrary-precision decimals or dates. Bytes are base64-encoded.
 */
export declare const PRISMA_SCALAR_TYPE_MAP: Record<string, string>;

/**
 * Resolve a Prisma field type to its TypeScript representation.
 *
 * Enum fields use their declared type name directly (the corresponding string
 * union type is generated separately). Scalar fields are mapped via
 * {@link PRISMA_SCALAR_TYPE_MAP}. Unknown types fall back to `unknown`.
 */
export declare function prismaTypeToTypeScript(type: string, kind: string): string;

