import type { DMMF, GeneratorOptions } from '@prisma/generator-helper'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generator'
import {
  generateCreateInput,
  generateEnumType,
  generateModelInterface,
  generateRestClientClass,
  generateUpdateInput,
  generateWhereUniqueInput,
} from '../template'
import { PRISMA_SCALAR_TYPE_MAP, prismaTypeToTypeScript } from '../type-map'

// ---------------------------------------------------------------------------
// Helpers to build mock DMMF structures
// ---------------------------------------------------------------------------

function mockField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: overrides.type,
    ...overrides,
  }
}

function mockModel(name: string, fields: DMMF.Field[], primaryKey: DMMF.PrimaryKey | null = null): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey,
  }
}

function mockEnum(name: string, values: string[]): DMMF.DatamodelEnum {
  return {
    name,
    values: values.map((v) => ({ name: v, dbName: null })),
  }
}

function mockGeneratorOptions(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
      output: { fromEnvVar: null, value: '/tmp/test-output' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    dmmf: {
      datamodel: { models, enums, types: [], indexes: [] },
      schema: {
        inputObjectTypes: { prisma: [] },
        outputObjectTypes: { model: [], prisma: [] },
        enumTypes: { prisma: [] },
      },
      mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
    },
    datasources: [],
    datamodel: '',
    version: 'test',
  }
}

// ---------------------------------------------------------------------------
// type-map.ts
// ---------------------------------------------------------------------------

describe('prismaTypeToTypeScript', () => {
  test('maps all known Prisma scalar types', () => {
    expect(prismaTypeToTypeScript('String', 'scalar')).toBe('string')
    expect(prismaTypeToTypeScript('Boolean', 'scalar')).toBe('boolean')
    expect(prismaTypeToTypeScript('Int', 'scalar')).toBe('number')
    expect(prismaTypeToTypeScript('Float', 'scalar')).toBe('number')
    expect(prismaTypeToTypeScript('BigInt', 'scalar')).toBe('bigint')
    expect(prismaTypeToTypeScript('Decimal', 'scalar')).toBe('string')
    expect(prismaTypeToTypeScript('DateTime', 'scalar')).toBe('string')
    expect(prismaTypeToTypeScript('Json', 'scalar')).toBe('unknown')
    expect(prismaTypeToTypeScript('Bytes', 'scalar')).toBe('string')
  })

  test('returns enum name for enum fields', () => {
    expect(prismaTypeToTypeScript('Role', 'enum')).toBe('Role')
  })

  test('falls back to unknown for unrecognised types', () => {
    expect(prismaTypeToTypeScript('SomeNewType', 'scalar')).toBe('unknown')
  })

  test('PRISMA_SCALAR_TYPE_MAP covers exactly nine types', () => {
    expect(Object.keys(PRISMA_SCALAR_TYPE_MAP)).toHaveLength(9)
  })
})

// ---------------------------------------------------------------------------
// template.ts — enum generation
// ---------------------------------------------------------------------------

describe('generateEnumType', () => {
  test('generates a string union type', () => {
    const result = generateEnumType(mockEnum('Role', ['USER', 'ADMIN']))
    expect(result).toBe("export type Role = 'USER' | 'ADMIN'")
  })

  test('handles a single-value enum', () => {
    const result = generateEnumType(mockEnum('Single', ['ONLY']))
    expect(result).toBe("export type Single = 'ONLY'")
  })
})

// ---------------------------------------------------------------------------
// template.ts — model interface
// ---------------------------------------------------------------------------

describe('generateModelInterface', () => {
  test('generates interface with scalar fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      mockField({ name: 'email', type: 'String' }),
      mockField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generateModelInterface(model, new Set())
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
  })

  test('skips relation (object) fields', () => {
    const model = mockModel('Post', [
      mockField({ name: 'id', type: 'Int', isId: true }),
      mockField({ name: 'author', type: 'User', kind: 'object' }),
    ])
    const result = generateModelInterface(model, new Set())
    expect(result).not.toContain('author')
  })

  test('handles list fields', () => {
    const model = mockModel('Tag', [
      mockField({ name: 'values', type: 'String', isList: true }),
    ])
    const result = generateModelInterface(model, new Set())
    expect(result).toContain('values: string[]')
  })

  test('handles enum fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])
    const result = generateModelInterface(model, new Set(['Role']))
    expect(result).toContain('role: Role')
  })
})

// ---------------------------------------------------------------------------
// template.ts — create input
// ---------------------------------------------------------------------------

describe('generateCreateInput', () => {
  test('omits auto-increment id fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      mockField({ name: 'email', type: 'String' }),
    ])
    const result = generateCreateInput(model, new Set())
    expect(result).not.toContain('id')
    expect(result).toContain('email: string')
  })

  test('makes fields with defaults optional', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      mockField({ name: 'role', type: 'String', hasDefaultValue: true }),
    ])
    const result = generateCreateInput(model, new Set())
    expect(result).toContain('role?: string')
  })

  test('makes nullable fields optional', () => {
    const model = mockModel('User', [
      mockField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generateCreateInput(model, new Set())
    expect(result).toContain('name?: string | null')
  })

  test('omits @updatedAt fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
    ])
    const result = generateCreateInput(model, new Set())
    expect(result).not.toContain('updatedAt')
  })

  test('omits isGenerated fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'computed', type: 'String', isGenerated: true }),
    ])
    const result = generateCreateInput(model, new Set())
    expect(result).not.toContain('computed')
  })
})

// ---------------------------------------------------------------------------
// template.ts — update input
// ---------------------------------------------------------------------------

describe('generateUpdateInput', () => {
  test('makes all fields optional', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true }),
      mockField({ name: 'email', type: 'String' }),
      mockField({ name: 'name', type: 'String' }),
    ])
    const result = generateUpdateInput(model, new Set())
    expect(result).toContain('email?: string')
    expect(result).toContain('name?: string')
  })

  test('omits id, read-only, and generated fields', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true }),
      mockField({ name: 'fk', type: 'Int', isReadOnly: true }),
      mockField({ name: 'computed', type: 'String', isGenerated: true }),
      mockField({ name: 'email', type: 'String' }),
    ])
    const result = generateUpdateInput(model, new Set())
    expect(result).not.toContain(' id')
    expect(result).not.toContain('fk')
    expect(result).not.toContain('computed')
    expect(result).toContain('email?: string')
  })
})

// ---------------------------------------------------------------------------
// template.ts — where unique input
// ---------------------------------------------------------------------------

describe('generateWhereUniqueInput', () => {
  test('uses @id field', () => {
    const model = mockModel('User', [
      mockField({ name: 'id', type: 'Int', isId: true }),
      mockField({ name: 'email', type: 'String' }),
    ])
    const result = generateWhereUniqueInput(model, new Set())
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id: number')
    expect(result).not.toContain('email')
  })

  test('uses composite primary key when no @id field', () => {
    const model = mockModel(
      'PostTag',
      [
        mockField({ name: 'postId', type: 'Int' }),
        mockField({ name: 'tagId', type: 'Int' }),
      ],
      { name: null, fields: ['postId', 'tagId'] },
    )
    const result = generateWhereUniqueInput(model, new Set())
    expect(result).toContain('postId: number')
    expect(result).toContain('tagId: number')
  })

  test('falls back to @unique field', () => {
    const model = mockModel('User', [
      mockField({ name: 'email', type: 'String', isUnique: true }),
      mockField({ name: 'name', type: 'String' }),
    ])
    const result = generateWhereUniqueInput(model, new Set())
    expect(result).toContain('email: string')
    expect(result).not.toContain('name')
  })

  test('falls back to Record when no unique identifier exists', () => {
    const model = mockModel('NoKey', [
      mockField({ name: 'data', type: 'String' }),
    ])
    const result = generateWhereUniqueInput(model, new Set())
    expect(result).toContain('Record<string, unknown>')
  })
})

// ---------------------------------------------------------------------------
// template.ts — REST client class
// ---------------------------------------------------------------------------

describe('generateRestClientClass', () => {
  test('generates class with CRUD methods for each model', () => {
    const result = generateRestClientClass(['User', 'Post'])
    expect(result).toContain('export class PrismaRestClient')
    expect(result).toContain('findManyUser')
    expect(result).toContain('findUniqueUser')
    expect(result).toContain('createUser')
    expect(result).toContain('updateUser')
    expect(result).toContain('deleteUser')
    expect(result).toContain('findManyPost')
    expect(result).toContain('findUniquePost')
    expect(result).toContain('createPost')
    expect(result).toContain('updatePost')
    expect(result).toContain('deletePost')
  })

  test('generates empty class for no models', () => {
    const result = generateRestClientClass([])
    expect(result).toContain('export class PrismaRestClient')
    expect(result).not.toContain('findMany')
  })

  test('uses lowercase model name in URL paths', () => {
    const result = generateRestClientClass(['UserProfile'])
    expect(result).toContain('/userprofile')
  })
})

// ---------------------------------------------------------------------------
// generator.ts — full generation
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  test('generates complete file for a schema with enums and models', () => {
    const options = mockGeneratorOptions(
      [
        mockModel('User', [
          mockField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          mockField({ name: 'email', type: 'String', isUnique: true }),
          mockField({ name: 'name', type: 'String', isRequired: false }),
          mockField({ name: 'role', type: 'Role', kind: 'enum' }),
          mockField({ name: 'posts', type: 'Post', kind: 'object', isList: true }),
          mockField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
          mockField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
        ]),
        mockModel('Post', [
          mockField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          mockField({ name: 'title', type: 'String' }),
          mockField({ name: 'content', type: 'String', isRequired: false }),
          mockField({ name: 'published', type: 'Boolean', hasDefaultValue: true }),
          mockField({ name: 'authorId', type: 'Int', isReadOnly: true }),
          mockField({ name: 'author', type: 'User', kind: 'object' }),
        ]),
      ],
      [mockEnum('Role', ['USER', 'ADMIN', 'MODERATOR'])],
    )

    const result = generateRestClient(options)

    // Header
    expect(result).toContain('AUTO-GENERATED FILE - DO NOT EDIT')
    expect(result).toContain('RestClientConfig')

    // Enum
    expect(result).toContain("export type Role = 'USER' | 'ADMIN' | 'MODERATOR'")

    // User model interface
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
    expect(result).toContain('role: Role')
    expect(result).not.toMatch(/export interface User \{[^}]*posts/) // no relation fields

    // User create input
    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toMatch(/UserCreateInput \{[^}]*email: string/) // required
    expect(result).toMatch(/UserCreateInput \{[^}]*name\?: string \| null/) // optional nullable
    expect(result).toMatch(/UserCreateInput \{[^}]*role: Role/) // required enum

    // User update input — no id, no updatedAt
    expect(result).toContain('export interface UserUpdateInput {')

    // Post model interface — includes authorId (readable)
    expect(result).toContain('export interface Post {')
    expect(result).toMatch(/export interface Post \{[^}]*authorId: number/)

    // Post update input — no authorId (read-only)
    expect(result).toContain('export interface PostUpdateInput {')
    expect(result).not.toMatch(/PostUpdateInput \{[^}]*authorId/)

    // REST client class
    expect(result).toContain('export class PrismaRestClient')
    expect(result).toContain('findManyUser')
    expect(result).toContain('createPost')
  })

  test('generates valid output for empty schema', () => {
    const options = mockGeneratorOptions([], [])
    const result = generateRestClient(options)
    expect(result).toContain('AUTO-GENERATED FILE')
    expect(result).toContain('export class PrismaRestClient')
  })

  test('handles all scalar types', () => {
    const options = mockGeneratorOptions([
      mockModel('AllTypes', [
        mockField({ name: 'id', type: 'Int', isId: true }),
        mockField({ name: 's', type: 'String' }),
        mockField({ name: 'b', type: 'Boolean' }),
        mockField({ name: 'i', type: 'Int' }),
        mockField({ name: 'f', type: 'Float' }),
        mockField({ name: 'bi', type: 'BigInt' }),
        mockField({ name: 'd', type: 'Decimal' }),
        mockField({ name: 'dt', type: 'DateTime' }),
        mockField({ name: 'j', type: 'Json' }),
        mockField({ name: 'by', type: 'Bytes' }),
      ]),
    ])
    const result = generateRestClient(options)
    expect(result).toContain('s: string')
    expect(result).toContain('b: boolean')
    expect(result).toContain('i: number')
    expect(result).toContain('f: number')
    expect(result).toContain('bi: bigint')
    expect(result).toContain('d: string')
    expect(result).toContain('dt: string')
    expect(result).toContain('j: unknown')
    expect(result).toContain('by: string')
  })
})

